var APIBasePath= window.ENV.APIURL;

function GetAllEnvName({ options }) {

  return (
    Object.keys(options).map((key)  => 
    <option >{key}</option>)
  );
  
}
function GetPieChart(summaryPass,summaryFail) {
  return {
    datasets: [
      {
        data: [summaryPass, summaryFail],
        backgroundColor: [
          getColor('success'),
          getColor('danger'),
        ],
      },
    ],
    labels: ['PASS', 'FAIL'],
  };
}
function ChangeJsoncontentforServer(ItemValue)
{
  try{
	var valueaf =[];
  if(ItemValue.includes("+"))
  {
	 valueaf = ItemValue.split('+')
	ItemValue= valueaf.join('auplussignau')
  }
  if(ItemValue.includes(":"))
  {
	 valueaf = ItemValue.split(':')
	ItemValue= valueaf.join('aucolumnsignau')
  }
  if(ItemValue.includes("{"))
  {
	 valueaf = ItemValue.split('{')
	ItemValue= valueaf.join('aucurlyopenbracketau')
  }
  if(ItemValue.includes("}"))
  {
	 valueaf = ItemValue.split('}')
	ItemValue= valueaf.join('aucurlyclosebracketau')
  }
  if(ItemValue.includes("["))
  {
	 valueaf = ItemValue.split('[')
	ItemValue= valueaf.join('aubigopenbracketau')
  }
  if(ItemValue.includes("]"))
  {
	 valueaf = ItemValue.split(']')
	ItemValue= valueaf.join('aubigclosebracketau')
  }
  if(ItemValue.includes("\""))
  {
	 valueaf = ItemValue.split('\"')
	ItemValue= valueaf.join('audoublequotesau')
  }
  if(ItemValue.includes("="))
  {
	 valueaf = ItemValue.split('=')
	ItemValue= valueaf.join('auequalsignau')
  }
 }
 catch(error)
 {}
  return ItemValue;
}
function GetLineChart(Component=[],summaryPass={},summaryFail={}) {
  return {
    labels: Component,
    datasets: [
      {
        label: 'PASS',
        backgroundColor: getColor('success'),
        borderColor: getColor('success'),
        borderWidth: 1,
        data: [
          ...summaryPass,
        ],
      },
      {
        label: 'FAIL',
        backgroundColor: getColor('danger'),
        borderColor: getColor('danger'),
        borderWidth: 1,
        data: [
          ...summaryFail,
        ],
      },
    ],
  };
}
function GetListvalueFromJsonResponce(options) 
{
  let allitem = []
     Object.keys(options).map((key) => (
      allitem.push(options[key])
	));
	return allitem;
}

function GetModule(TestSuite,Index,executableTestscript)
{
  var Mo= TestSuite[executableTestscript[Index]-1].moduleName;
  return Mo;
}

function GetTestID(TestSuite,Index,executableTestscript)
{
  var testID =TestSuite[executableTestscript[Index]-1].testid;
  return testID;
}

function GetTestName(TestSuite,Index,executableTestscript)
{
  var testName= TestSuite[executableTestscript[Index]-1].testcasename;
  return testName;
}

function TestInformationForTestSummaryReports(Mo,testID,testName,Status,reportPath,duration)
{
  var jstestStepData={};
  jstestStepData["Module"]=Mo;
  jstestStepData["testid"]=testID
  jstestStepData["testcasename"]=testName;
  jstestStepData["status"]=Status;
  reportPath= reportPath.split('\\').join('{')
  jstestStepData["reportpath"]=reportPath;
  jstestStepData["duration"]=duration;
  return jstestStepData;
}

class executionlabpage extends React.Component{
  constructor(props)
  {
		super(props);
    this.state=
    {
      tabIndex:0,
      ENV:'',
      Browser:'',
      screenshot :'FOR EACH STEP',
      runAt :'SELENIUM GRID',
      EmailTrigger:'NO',
      FromEmail:'',
      FromPassword:'',
      ReceiverEmail:'',
      checkFromEmai:false,
      checkPassword:false,
      checkRecemail:false,
      testSuiteResponce:[],
      testSuiteData: [],
      modal: false,
      modalValidationText:'',
      selected:[],
      showProgressBar:false,
      showProgressText:false,
      totalexecutedTestcasen:0,
      scriptResponce :'Not Started',
      wait:false,
      summaryPass:0,
      summaryFail:0,
      //allModule :['PLP','PIP'],
      allModuleName:[],
      allModule :[],
      allPassModuleWise:[],
      allFailModuleWise:[],
      allHTMLHyperlink:[],
      ExecutionSuitePath:'',
      ConfigurationFile:[],
      CommonTestData:[],
      loader:false,
      loaderLoadTestScripts:false,
      ScriptParallelCheck:false,
      seGridResponse:false,
      ExecutionNature:'',
      checkExecutionNature:false,
      feedbackExecutionNature:'Debugging:Reports will not included in dashboard.',
      DeviceIP:'',
      pageloadingStatus :true,
      DefaultEnvironment : '',
      EnvName:[],

    }

    const GetLoaderData = async () => 
    {
      this.setState({pageloadingStatus:true})
      const configPage = await fetch(APIBasePath+'apiconfig');
      const configPageResponse = await configPage.json();
      if(Object.keys(configPageResponse).length>0)
      {
          this.setState({ConfigurationFile:configPageResponse});
          this.setState({DefaultEnvironment : configPageResponse['EXECUTIONSETUP']['DefaultEnvironment']});
          this.setState({EnvName:configPageResponse['ENVIRONMENTSETUP']})
          this.setState({pageloadingStatus:false})
      }
    }
    GetLoaderData()

  }

  OpenTestSummaryFile()
  {
    var ReportsPath = this.state.ExecutionSuitePath;
    if(ReportsPath.trim()==="")
    {
      return;
    }
    window.open(ReportsPath);
    
  }
  LoadAllAPIScripts()
  {
    const GetApiScripts = async () => 
    {
      this.setState({loaderLoadTestScripts:true});
      this.setState({loader:true});
      const configPage = await fetch(APIBasePath+'apiexecution');
      const configPageResponse = await configPage.json();
      this.setState({testSuiteData:configPageResponse});
      this.setState({selected:[]});
      this.setState({loaderLoadTestScripts:false});
      this.setState({loader:false});
    }
    GetApiScripts()
  }

  ExecuteAPIScripts()
  {
    var env = this.state.DefaultEnvironment;
    var testscriptCount = this.state.testSuiteData;
    if(testscriptCount.length===0)
    {
     this.setState({modal:true})
     return this.setState({modalValidationText:'Please Load test scripts before execution.'})
    }
    var totalselectedTestScript = this.state.selected;
    if(totalselectedTestScript.length===0)
    {
     this.setState({modal:true})
     return this.setState({modalValidationText:'Please select test script for execution.'})
    }
    var allScriptsItem={}
    console.log(testscriptCount)
    for(let i=0;i<totalselectedTestScript.length;i++)
    {
      var index = Number(totalselectedTestScript[i])-1;
      var TestName = testscriptCount[index].testcasename;
      var Module = testscriptCount[index].moduleName;
      allScriptsItem[i]=Module+'@'+TestName;
    }
    var configjson = ChangeJsoncontentforServer(JSON.stringify(allScriptsItem));
    var configAPI =APIBasePath+'apiexecution?env='+env;
    var requestOptions = {
      method: 'POST',
     headers: {"Accept": "application/json; odata=verbose",'Content-type': 'application/x-www-form-urlencoded'},
      body: configjson
    };
    const Execution = async () => 
    {
      this.setState({loader:true})
      this.setState({pageloadingStatus:true})
      const Request = await fetch(configAPI,requestOptions);
      const Response = await Request.json();
      this.setState({loader:false})
      this.setState({pageloadingStatus:false})
      var allTestSuiteData= this.state.testSuiteData;
      for(let i=0;i<totalselectedTestScript.length;i++)
      {
        var index = Number(totalselectedTestScript[i])-1;
        var TestName = allTestSuiteData[index].testcasename;
        var Status = Response[TestName];
        allTestSuiteData[index].status=Status;
      }
      this.setState({testSuiteData:allTestSuiteData})
    }
    Execution()
  }
  UpdateEnv(event)
  {
    var env = event.target.value;
    if(env !== this.state.DefaultEnvironment)
    {
      this.setState({DefaultEnvironment: env})
    }
    
    
  }
  ExecuteTestScripts()
  {
    // Show a pop up if it works
    this.setState({showProgressBar:false});
    this.setState({showProgressText:false});
    this.setState({totalexecutedTestcasen:0});
     var testscriptCount = this.state.testSuiteData.length;
    
     if(testscriptCount===0)
     {
      this.setState({modal:true})
      return this.setState({modalValidationText:'Please Load test scripts before execution.'})
     }
     var email= this.state.EmailTrigger;
     var From = this.state.FromEmail;
     var PasswordUI = this.state.FromPassword;
     var Receiver = this.state.ReceiverEmail;
     var validationMessage='';
     var DashboardReportingCheck = this.state.ExecutionNature;
     var clientMachineId= this.state.DeviceIP;
     if(DashboardReportingCheck.trim()==="")
     {
      this.setState({checkExecutionNature:true})
      return;
     }
     else
     {
      this.setState({checkExecutionNature:false})
     }
     if(email==="YES")
     {
        if(From.trim()==="")
        {
          this.setState({checkFromEmai:true});
          validationMessage= "From Email can not be blank."
        }
        if(PasswordUI.trim()==="")
        {
          this.setState({checkPassword:true});
          validationMessage= validationMessage+"Password can not be blank."
        }
        if(Receiver.trim()==="")
        {
          this.setState({checkRecemail:true});
          validationMessage= validationMessage+"Receiver Email can not be blank."
        }
        if(validationMessage.trim() !=="")
        {
          this.setState({modal:true})
          return this.setState({modalValidationText:validationMessage})
        }
     }
     var totalselectedTestScript = this.state.selected.length;
     if(totalselectedTestScript===0)
     {
      this.setState({modal:true})
      return this.setState({modalValidationText:'Please select test script for execution.'})
     }
     var StartTime = new Date().toLocaleString();
     //@ 
     const executableTestscript = this.state.selected;
     this.setState({summaryPass:0})
     this.setState({summaryFail:0})
     var TotalPass=0;
     var TotalFail =0;
    
      //@ set total Pass and Fail
      var GraphItem = this.state.testSuiteData;
      for(let i=0;i<GraphItem.length;i++)
      {
        var StatusGraph = GraphItem[i].status
        if(StatusGraph==="PASS")
        {
          TotalPass=TotalPass+1;
          this.setState({summaryPass:TotalPass})
        }
        if(StatusGraph==="FAIL")
        {
          TotalFail=TotalFail+1;
          this.setState({summaryFail:TotalFail})
        }
      }
     var scriptcounter=0;
     var jstestStepDatacollection={};
     totalselectedTestScript = this.state.selected.length
     var En = this.state.ENV 
     var Br = this.state.Browser;
     var Sc= this.state.screenshot;
     var Ru= this.state.runAt;
     var HubName= this.state.ConfigurationFile.HUBMachineName;
     var portNumber= this.state.ConfigurationFile.HUBPort;
     var delayAPI =APIBasePath+'execution?delay=1000';

     //############ NEW Code for Execution#################################

     // Check Selenium Grid
     
     const TestSuiteStructure = this.state.testSuiteData;
     const Itemmodule = this.state.allModule;
     const seGridRequest = async () => 
     {
      this.setState({pageloadingStatus:true});
       const APIReq = await fetch(APIBasePath+'segrid?hubname='+HubName+'&portnumber='+portNumber+'&browser='+Br)
       const APIResponse = await APIReq.json();
       this.setState({pageloadingStatus:false});
       if(!APIResponse.success)
       {
        this.setState({seGridResponse:false})
        this.setState({modal:true})
        return this.setState({modalValidationText:APIResponse.servermessage})
       }
       else
       {
          this.setState({seGridResponse:true})
       }
     }
    seGridRequest();

    setTimeout(() => 
    {
      if(this.state.seGridResponse)
      {
      this.setState({showProgressBar:true});
      this.setState({showProgressText:true});
      for (let counter=0; counter<Number(totalselectedTestScript); counter++) 
      {
         task(counter);
         const Delayrequest = async () => 
         {
           const Delayresponse = await fetch(delayAPI);
           const Delayjson = await Delayresponse.json();
           var DelaycheckStatus= Delayjson.success 
           if(DelaycheckStatus==="PASS")
           {
             task(counter);
              /********** Get Test case Information*************** */
              var Mo= GetModule(TestSuiteStructure,counter,executableTestscript);
              var testID =GetTestID(TestSuiteStructure,counter,executableTestscript);
              var testName= GetTestName(TestSuiteStructure,counter,executableTestscript);
              var Status='';
              var HtmlPath='';
              var TestRunDuration='';
             //******  Update Test Status before execution in Grid ***************************
             TestSuiteStructure[executableTestscript[counter]-1].status= 'In-Progress';
             this.setState({testSuiteData:TestSuiteStructure});
             //******  Test Script execution API*************************************************
              var API = APIBasePath+'execution?module='+Mo+'&testid='+testID+'&testcasename='+testName+'&env='+En+'&browser='+Br+'&runat='+Ru+'&screenshot='+Sc+'&hubmachine='+HubName+'&portnumber='+portNumber+'&executionnature='+DashboardReportingCheck+'&clientmachineid='+clientMachineId;
             const request = async () => 
             {
              this.setState({pageloadingStatus:true});
               const response = await fetch(API);
               const json = await response.json();
               this.setState({pageloadingStatus:false});
               Status=json.status;
               HtmlPath=json.htmlPath;
               TestRunDuration=json.testRunDuration;
               //******  Update Test Status and Hyperlink after execution in Grid ********************************
               TestSuiteStructure[executableTestscript[counter]-1].status= Status;
               this.setState({testSuiteData:TestSuiteStructure});
                var testhtml = this.state.allHTMLHyperlink;
                testhtml['RowId'+executableTestscript[counter]]=HtmlPath;
                this.setState({ allHTMLHyperlink: testhtml});
               //******  Save Total Pass Fail Count for Summary Report********************************************
               if(Status==="PASS")
               {
                 TotalPass=TotalPass+1;
               }
               if(Status==="FAIL")
               {
                 TotalFail=TotalFail+1;
               }
               //******  Test Information for Summary Report ****************************************************
               jstestStepDatacollection[counter+1]=TestInformationForTestSummaryReports(Mo,testID,testName,Status,HtmlPath,TestRunDuration);
               
               /*****************************************Module Pass Fail *********************************** */
               var pushPass =[]
               var pushFail=[]
               var modulefound =0;
               for(let i=0;i<Itemmodule.length;i++)
               {
                 var modulePass=0
                 var moduleFail=0
                 for(let j=modulefound;j<TestSuiteStructure.length;j++)
                 {
                     var RunTimeModuleName = TestSuiteStructure[j].moduleName;
                     if(RunTimeModuleName===Itemmodule[i])
                     {
                     var checkstatus = TestSuiteStructure[j].status
                     if(checkstatus==="PASS")
                     {
                       modulePass=modulePass+1;
                     }
                     if(checkstatus==="FAIL")
                     {
                       moduleFail=moduleFail+1;
                     }
                     }
                     else
                     {
                       modulefound =j;
                       break;
                     }
                 }
                 pushPass.push(modulePass);
                 pushFail.push(moduleFail)
               }
               /****************** Check all script is executed ************************************************/
               scriptcounter= Number(scriptcounter)+1;
               this.setState({ScriptParallelCheck:true})
               if(scriptcounter===totalselectedTestScript)
               {
                 this.setState({summaryPass:TotalPass})
                 this.setState({summaryFail:TotalFail})
                 this.setState({allPassModuleWise:pushPass});
                 this.setState({allFailModuleWise:pushFail});
                 this.setState({showProgressBar:false});
                 this.setState({showProgressText:false});
                 this.setState({totalexecutedTestcasen:0});
                 //@ set email option
                 jstestStepDatacollection["EmailOption"]=email;
                 jstestStepDatacollection["FormEmailAddress"]=From;
                 jstestStepDatacollection["FEmailPassword"]=PasswordUI;
                 jstestStepDatacollection["ReceiverEmailAddress"]=Receiver;
                 jstestStepDatacollection["Browser"]=Br;
                 var EndTime = new Date().toLocaleString();
                 jstestStepDatacollection["StartTime"]=StartTime;
                 jstestStepDatacollection["EndTime"]=new Date().toLocaleString();
                 var postjson = JSON.stringify(jstestStepDatacollection);
                 var requestOptions = 
                 {
                   method: 'POST',
                   headers: {"Accept": "application/json; odata=verbose",'Content-type': 'application/x-www-form-urlencoded'},
                   body: postjson
                 };
                 const TestSuiteandSummary = async () => 
                 {
                  this.setState({pageloadingStatus:true});
                   const APIRequest = await fetch(APIBasePath+'execution?env='+En+'&executionnature='+DashboardReportingCheck+'&clientmachineid='+clientMachineId,requestOptions);
                   const APIResponse = await APIRequest.json();
                   this.setState({pageloadingStatus:false});
                   if(APIResponse.success.toLowerCase()==='pass')
                   {
                     var HtmlPath=APIResponse.testSuitePath;
                     this.setState({ExecutionSuitePath:HtmlPath})
                   }
                 }
                 TestSuiteandSummary();
               }
             }
             request();
           }
         }
         Delayrequest()
        } 
        function task(p) 
        { 
          setTimeout(function() 
          {
          }, 4000 * p); 
        }
      }
    }, 10000);
    

  }

  handleOnSelect = (row, isSelect) => {
    if (isSelect) {
      this.setState(() => ({
        selected: [...this.state.selected, row.id]
      }));
    } else {
      this.setState(() => ({
        selected: this.state.selected.filter(x => x !== row.id)
      }));
    }
  }

  handleOnSelectAll = (isSelect, rows) => {
    const ids = rows.map(r => r.id);
    if (isSelect) {
      this.setState(() => ({
        selected: ids
      }));
    } else {
      this.setState(() => ({
        selected: []
      }));
    }
  }

  updateENV(event){
		this.setState({ENV : event.target.value})
    }
    updateBrowser(event){
      this.setState({Browser : event.target.value})
      }
    updateScreenshot(event){
      this.setState({screenshot : event.target.value})
      }
      updateEmailOption(event)
      {
        var emailoption = event.target.value;
        this.setState({EmailTrigger : event.target.value})
        if(emailoption==="YES")
        {
          this.setState({FromEmail:this.state.ConfigurationFile.SenderEmail});
          this.setState({FromPassword:this.state.ConfigurationFile.SenderPassword});
          this.setState({ReceiverEmail:this.state.ConfigurationFile.ReceiverEmail});

        }
        else
        {
          this.setState({FromEmail:''});
          this.setState({FromPassword:''});
          this.setState({ReceiverEmail:''});
        }
      }
      UpdateFromEmail(event)
      {
        this.setState({checkFromEmai:false})
        this.setState({FromEmail : event.target.value})
      }
      UpdatePassword(event)
      {
        this.setState({checkPassword:false})
        this.setState({FromPassword : event.target.value})
      }
      UpdateRecieverEmail(event)
      {
        this.setState({checkRecemail:false})
        this.setState({ReceiverEmail : event.target.value})
      }
      UpdateExecutionNature(event){
        this.setState({ExecutionNature : event.target.value})
        this.setState({checkExecutionNature:false})
        }

      toggle = modalType => () => {
        if (!modalType) {
          return this.setState({
          modal: !this.state.modal,
          });
        }
      
        this.setState({
          [`modal_${modalType}`]: !this.state[`modal_${modalType}`],
        });
        };
        

  render() {


	  const selectRow = {
      mode: 'checkbox',
      selected: this.state.selected,
      onSelect: this.handleOnSelect,
      onSelectAll: this.handleOnSelectAll
      };
    const options = {
      sizePerPage: 10,
      hideSizePerPage: true,
      hidePageListOnlyOnePage: true
      };
    const testSuitecolumns = [
      {
        dataField: 'id',
        text: '#',
        headerStyle: { width: '50px' },
      },
      {
        dataField: 'moduleName',
        text: 'Module Name',
        headerStyle: { width: '200px' },
        filter: textFilter()
      },
      {
        dataField: 'testcasename',
        text: 'Test Case Name',
        filter: textFilter()
      },
      {
        dataField: 'status',
        text: 'Status',
        headerStyle: { width: '120px' },
        filter: textFilter(),
        style: (newValue) => {
          if (newValue=== 'FAIL') {
            return {
              backgroundColor: '#dc3545'
            };
          };
          if (newValue=== 'PASS') {
            return {
              backgroundColor: '#28a745'
            };
          };
        }
        
      }
    ];

  return (
    <Page title="Execution Lab" breadcrumbs={[{ name: 'Execution Lab', active: true }]}>
      <Loader 
        type="ThreeDots"
        color="#00BFFF"
        height={50}
        width={100}
        timeout={120000} //3 secs
        visible = {this.state.loader}
      /> 
	  <Row>
    <Col lg={4} md={4} sm={4} xs={4}>
          <Card>
            <CardHeader>Environment*
            </CardHeader>
            <CardBody>
              <Form>
              <FormGroup row>
                  <Label for="exampleSelect" sm={6}>
                    Environment*
                  </Label>
                  <Col>
                    <Input type="select" name="envlist" value ={this.state.DefaultEnvironment} onChange={this.UpdateEnv.bind(this)}>
                      <GetAllEnvName options={this.state.EnvName} />
					          </Input>
                  </Col>
                </FormGroup>
              </Form>
            </CardBody>
          </Card>
        </Col>
	  	<Col lg={12} md={6} sm={6} xs={12}>
          <Card>
            <CardHeader>Executable Test Scripts
            <Button disabled={this.state.pageloadingStatus} onClick={this.LoadAllAPIScripts.bind(this)} name ="loadTestSuite" color="primary">Load Test Scripts</Button>
            <Button disabled={this.state.pageloadingStatus} onClick={this.ExecuteAPIScripts.bind(this)} name ="executeTC" color="primary">Execute Test Scripts</Button>
             <div  style={{visibility: this.state.showProgressText ? 'visible' : 'hidden' }} className="text-center">{this.state.totalexecutedTestcasen} of {this.state.selected.length}</div>
              <Loader 
                type="ThreeDots"
                color="#00BFFF"
                height={30}
                width={100}
                timeout={120000} //3 secs
                visible = {this.state.loaderLoadTestScripts}
              />
              <Progress style={{visibility: this.state.showProgressBar ? 'visible' : 'hidden' }} value= {this.state.totalexecutedTestcasen} max={this.state.selected.length} />
               <Modal
                      isOpen={this.state.modal}
                      toggle={this.toggle()}
                      className={this.props.className}>
                      <ModalHeader  toggle={this.toggle()}> Information</ModalHeader>
                      <ModalBody >
                        {this.state.modalValidationText}
                      </ModalBody>
                      <ModalFooter>
                        <Button disabled={this.state.pageloadingStatus} color="secondary" onClick={this.toggle()}>
                          OK
                        </Button>
                      </ModalFooter>
            </Modal>
              
            </CardHeader>
            <CardBody>
            <BootstrapTable
              keyField="id"
              data={ this.state.testSuiteData }
              columns={ testSuitecolumns }
              striped
              hover
              condensed
              pagination={ paginationFactory(options) }
              selectRow={ selectRow }
              filter={ filterFactory() }
              disabled={this.state.pageloadingStatus}
            />
            </CardBody>
          </Card>
        </Col>			
    </Row>
		<Row>
        <Col lg={4} md={6} sm={6} xs={12}>
          <Card>
            <CardHeader>Total Pass Fail Count</CardHeader>
			        <CardBody >
              <Pie disabled={this.state.pageloadingStatus} data={GetPieChart(this.state.summaryPass,this.state.summaryFail)} />
            </CardBody>
          </Card>
        </Col>
		<Col lg={8} md={6} sm={6} xs={12}>
		<Card>
            <CardHeader>Pass Fail Count Module wise</CardHeader>
			      <CardBody>
            <Bar disabled={this.state.pageloadingStatus}
                data={GetLineChart(this.state.allModule,this.state.allPassModuleWise,this.state.allFailModuleWise)}
              />
            </CardBody>
          </Card>
        </Col>
      </Row>
      </Page>
   );
}
};


